def solve(nums, target):
    left, right = 0, len(nums) - 1
    while left < right:
        total = nums[left] + nums[right]
        if total == target:
            return left, right
        if total < target:
            left += 1
        else:
            right -= 1
    return -1, -1

# Additional checks for pitfalls
def check_indices(nums, target):
    result = solve(nums, target)
    if result == (-1, -1):
        return "No solution found"

    left, right = result
    if left == right or left < 0 or right < 0 or left >= len(nums) or right >= len(nums):
        return "Invalid indices returned"

    return result
